// Recorrer cada item entrante
return items.map(item => {

  // 1. Obtener el texto del campo output
  let raw = item.json.output;

  // 2. Limpiar backticks y etiquetas ```json
  raw = raw.replace(/```json/g, "")
           .replace(/```/g, "")
           .trim();

  // 3. Parsear el JSON interno
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    throw new Error("Error parseando JSON interno: " + err.message);
  }

  // 4. Devolver todos los campos incluyendo datos_video, datos_imagen y datos_publicacion
  return {
    json: {
      respuesta: parsed.respuesta,
      generar: parsed.generar,
      publicar: parsed.publicar || false,
      tipo: parsed.tipo,
      datos_video: parsed.datos_video || {
        objetivo: null,
        modelo: null,
        url_1: null,
        url_2: null,
        url_3: null,
        url_4: null,
        url_5: null,
        servicio_video: null,
        formato_de_imagen_video: null,
        duracion_video: null,
        descripcion_imagenes_video: null,
        url_logo: null
      },
      datos_imagen: parsed.datos_imagen || {
        prompt: null,
        modelo: null,
        image_size: null,
        url_1: null,
        url_2: null,
        url_3: null,
        url_4: null,
        url_5: null
      },
      datos_publicacion: parsed.datos_publicacion || {
        tipo_contenido: null,
        url_1: null,
        url_2: null,
        url_3: null,
        url_4: null,
        url_5: null,
        url_6: null,
        url_7: null,
        url_8: null,
        url_9: null,
        url_10: null,
        nombre_imagen_1: null,
        nombre_imagen_2: null,
        nombre_imagen_3: null,
        nombre_imagen_4: null,
        nombre_imagen_5: null,
        nombre_imagen_6: null,
        nombre_imagen_7: null,
        nombre_imagen_8: null,
        nombre_imagen_9: null,
        nombre_imagen_10: null
      }
    }
  };
});

// Obtener el dato del trigger de Telegram
const rawData = $('Telegram Trigger').first().json.callback_query.data;

// Verificar si contiene coma (dos campos) o no (un campo)
let result = {};

if (rawData.includes(',')) {
  // Si hay coma, separar en dos campos
  const parts = rawData.split(',');
  result.campo1 = parts[0].trim();
  result.campo2 = parts[1].trim();
} else {
  // Si no hay coma, solo un campo
  result.campo1 = rawData.trim();
}

// Determinar el tipo basado en campo1
const campo1Lower = result.campo1.toLowerCase();

if (campo1Lower.includes('imagen')) {
  result.tipo_creativo = 'imagen';
} else if (campo1Lower.includes('video')) {
  result.tipo_creativo = 'video';
} else {
  result.tipo_creativo = 'desconocido';
}

// Determinar la acción (publicar o no publicar)
if (campo1Lower.includes('publicar_imagen') || campo1Lower.includes('publicar_video')) {
  result.accion = 'publicar';
} else if (campo1Lower.includes('no_publicar_imagen') || campo1Lower.includes('no_publicar_video')) {
  result.accion = 'no_publicar';
} else if (campo1Lower.includes('bueno')) {
  result.accion = 'bueno';
} else if (campo1Lower.includes('malo')) {
  result.accion = 'malo';
}

return [{
  json: result
}];

